Sburb.AlterniaboundBabies = {"count": 176, "cellW": 260, "cellH": 180, "numCols": 14, "numRows": 13, "babiesCell": 38, "frameInterval": 2, "narration": "@! You are now Past Karkat. You are pretty much freaking the fuck out."};
